import sailpoint.object.*;
import sailpoint.tools.*;
import java.util.*;

try {
  requestId = UUID.randomUUID().toString();
  log.info("RequestID: " + requestId);
  log.info("GroupName: " + groupName);
  log.info("AppName: " + applicationName);

  // Get the AD application
  Workflow wf = context.getObjectByName(Workflow.class, "Create AD Group from API");
  Application app = context.getObjectByName(Application.class, applicationName);

  if (app == null) {
    errorMessage = "Application not found";
    isSuccess = false;
  } else {
    log.info("App found");

    // Create provisioning plan
    ProvisioningPlan plan = new ProvisioningPlan();
    ProvisioningPlan.AccountRequest acctReq = new ProvisioningPlan.AccountRequest(
      ProvisioningPlan.AccountRequest.Type.Create, applicationName, null, null);

    // Add attributes
    acctReq.add(new ProvisioningPlan.AttributeRequest("sAMAccountName", ProvisioningPlan.Operation.Set, groupName));
    acctReq.add(new ProvisioningPlan.AttributeRequest("cn", ProvisioningPlan.Operation.Set, groupName));
    acctReq.add(new ProvisioningPlan.AttributeRequest("displayName", ProvisioningPlan.Operation.Set, groupName));
    acctReq.add(new ProvisioningPlan.AttributeRequest("description", ProvisioningPlan.Operation.Set, groupDescription));
    acctReq.add(new ProvisioningPlan.AttributeRequest("groupType", ProvisioningPlan.Operation.Set, groupType));
    acctReq.add(new ProvisioningPlan.AttributeRequest("groupScope", ProvisioningPlan.Operation.Set, groupScope));
    acctReq.add(new ProvisioningPlan.AttributeRequest("ou", ProvisioningPlan.Operation.Set, organizationalUnit));
    acctReq.add(new ProvisioningPlan.AttributeRequest("managedBy", ProvisioningPlan.Operation.Set, groupOwner));

    if (groupEmail != null && groupEmail.length() > 0) {
      acctReq.add(new ProvisioningPlan.AttributeRequest("mail", ProvisioningPlan.Operation.Set, groupEmail));
    }

    plan.add(acctReq);

    // Execute plan
    sailpoint.connector.Connector connector = app.getConnector();
    if (connector != null) {
      connector.provision(context, app, plan);
      log.info("SUCCESS: Group created");
      isSuccess = true;
    } else {
      errorMessage = "No connector";
      isSuccess = false;
    }
  }

} catch (Exception e) {
  errorMessage = e.getMessage();
  isSuccess = false;
  log.error("Error: " + errorMessage);
}
